            builders.Add(_services.AddHttpClient<IBudgetsApi, BudgetsApi>("AsanaApiClient.Api.IBudgetsApi", client));
            builders.Add(_services.AddHttpClient<ICustomFieldSettingsApi, CustomFieldSettingsApi>("AsanaApiClient.Api.ICustomFieldSettingsApi", client));
            builders.Add(_services.AddHttpClient<ICustomFieldsApi, CustomFieldsApi>("AsanaApiClient.Api.ICustomFieldsApi", client));
            builders.Add(_services.AddHttpClient<ICustomTypesApi, CustomTypesApi>("AsanaApiClient.Api.ICustomTypesApi", client));
            builders.Add(_services.AddHttpClient<IEventsApi, EventsApi>("AsanaApiClient.Api.IEventsApi", client));
            builders.Add(_services.AddHttpClient<IExportsApi, ExportsApi>("AsanaApiClient.Api.IExportsApi", client));
            builders.Add(_services.AddHttpClient<IGoalRelationshipsApi, GoalRelationshipsApi>("AsanaApiClient.Api.IGoalRelationshipsApi", client));
